/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Inventário"
//Report Template Source Header if &Context.EmpCod = 0 loadWWPContext.Call(&Context) Endif
For Each ORder EmpCod, FilCod Where EmpCod = &Context.EmpCod Where FilCod = &Context.FilCod &AppName = FilFan
&AddressLine1 = &Today.ToFormattedString() + ' ' + &Time.Trim() //FilLogNro.Trim() + ' - ' + FilBai.Trim() + ', '+ FilCidCodNomUfe.Trim()
&AddressLine2 = FilFonNum.Trim() if not FilEml.IsEmpty() if not &AddressLine2.IsEmpty() &AddressLine2 += ' / ' Endif &AddressLine2 += FilEml.Trim() Endif Exit EndFor
Print printTitle End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &FilterFullText.IsEmpty() print printBlockFilterFilterFullText EndIf If not &FilInvEmpCod.IsEmpty() print printBlockFilterFilInvEmpCod EndIf If not &FilInvFilCod.IsEmpty() print printBlockFilterFilInvFilCod EndIf If not &FilInvAno.IsEmpty() print printBlockFilterFilInvAno EndIf If not &FilInvMes.IsEmpty() &FilterFilInvMesValueDescription = '' Do Case Case &FilInvMes = 1 &FilterFilInvMesValueDescription = "Janeiro"
Case &FilInvMes = 2 &FilterFilInvMesValueDescription = "Fevereiro"
Case &FilInvMes = 3 &FilterFilInvMesValueDescription = "Março"
Case &FilInvMes = 4 &FilterFilInvMesValueDescription = "Abril"
Case &FilInvMes = 5 &FilterFilInvMesValueDescription = "Maio"
Case &FilInvMes = 6 &FilterFilInvMesValueDescription = "Junho"
Case &FilInvMes = 7 &FilterFilInvMesValueDescription = "Julho"
Case &FilInvMes = 8 &FilterFilInvMesValueDescription = "Agosto"
Case &FilInvMes = 9 &FilterFilInvMesValueDescription = "Setembro"
Case &FilInvMes = 10 &FilterFilInvMesValueDescription = "Outubro"
Case &FilInvMes = 11 &FilterFilInvMesValueDescription = "Novembro"
Case &FilInvMes = 12 &FilterFilInvMesValueDescription = "Dezembro"
EndCase
print printBlockFilterFilInvMes EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each Inventario.Produtos order InvProGraRefPadL when &OrderedBy = 1 order InvProNom when &OrderedBy = 2 AND &OrderedDsc = False order (InvProNom) when &OrderedBy = 2 AND &OrderedDsc = True order InvProGraRef when &OrderedBy = 3 AND &OrderedDsc = False order (InvProGraRef) when &OrderedBy = 3 AND &OrderedDsc = True order InvProVlrCus when &OrderedBy = 4 AND &OrderedDsc = False order (InvProVlrCus) when &OrderedBy = 4 AND &OrderedDsc = True order InvProQtd when &OrderedBy = 5 AND &OrderedDsc = False order (InvProQtd) when &OrderedBy = 5 AND &OrderedDsc = True order InvProQtdAtu when &OrderedBy = 6 AND &OrderedDsc = False order (InvProQtdAtu) when &OrderedBy = 6 AND &OrderedDsc = True order InvGrupHie when &OrderedBy = 7 AND &OrderedDsc = False order (InvGrupHie) when &OrderedBy = 7 AND &OrderedDsc = True order InvGrupNomCmp when &OrderedBy = 8 AND &OrderedDsc = False order (InvGrupNomCmp) when &OrderedBy = 8 AND &OrderedDsc = True
using DSwpInventarioItens(&FilterFullText, &FilInvEmpCod, &FilInvFilCod, &FilInvAno, &FilInvMes)
Do 'BeforePrintLine' print printBlockLines_data &GridCount += 1 &TotInvProQtd = InvProQtd + &TotInvProQtd &TotInvProVlrCusTot = InvProVlrCusTot + &TotInvProVlrCusTot
Do 'AfterPrintLine' EndFor
Do 'PrintTotalizers'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintTotalizers'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TotValueInvProGraRef = "WWP_TotalizerCount" + trim(&GridCount.ToFormattedString()) &TotValueInvProQtd = trim(&TotInvProQtd.ToFormattedString()) &TotValueInvProVlrCusTot = trim(&TotInvProVlrCusTot.ToFormattedString()) print printBlockLines_Totalizers
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wpInventarioItensGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wpInventarioItensGridState")) Else &GridState.FromXml(&Session.Get(!"wpInventarioItensGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILTERFULLTEXT" &FilterFullText.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVEMPCOD" &FilInvEmpCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVFILCOD" &FilInvFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVANO" &FilInvAno.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILINVMES" &FilInvMes.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforePrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterPrintLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

Output_file("ExportReportwpInventarioItens","PDF");

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
